import {
  Envelope1,
  Facebook,
  Instagram1,
  Linkedin,
  MapMarker5,
  Telephone1,
  Twitter,
} from '@tailgrids/icons';

// Type definitions
interface ContactInfo {
  icon: React.ReactNode;
  text: string;
}

interface Badge {
  text: string;
  className: string;
  icon?: React.ReactNode;
}

interface NavLink {
  text: string;
  href: string;
  badge?: Badge;
}

interface NavSection {
  title: string;
  links: NavLink[];
}

interface SocialLink {
  icon: React.ReactNode;
  href: string;
}

// Props interfaces
interface ContactItemProps {
  icon: React.ReactNode;
  text: string;
}

interface NavSectionProps {
  title: string;
  links: NavLink[];
}

interface SocialLinkProps {
  icon: React.ReactNode;
  href: string;
}

