// Sub-components
const ContactItem: React.FC<ContactItemProps> = ({ icon, text }) => (
  <li className="text-text-100 flex items-start gap-2 text-base font-medium">
    <span className="shrink-0">{icon}</span>
    {text}
  </li>
);

const NavSection: React.FC<NavSectionProps> = ({ title, links }) => (
  <div>
    <h4 className="text-title-50 mb-6 text-lg font-semibold">{title}</h4>
    <nav>
      <ul className="space-y-3">
        {links.map((link: NavLink, index: number) => (
          <li key={index}>
            <a
              href={link.href}
              className="text-text-100 hover:text-primary-500 leading-6 font-medium"
            >
              {link.text}
              {link.badge && (
                <span className={link.badge.className}>
                  {link.badge.icon}
                  {link.badge.text}
                </span>
              )}
            </a>
          </li>
        ))}
      </ul>
    </nav>
  </div>
);

const SocialLink: React.FC<SocialLinkProps> = ({ icon, href }) => (
  <a href={href} className="text-text-200 hover:text-text-50">
    <span>{icon}</span>
  </a>
);

